$dir = 'C:\SAPIForVOICEVOX32'
Write-Output "===== $dir 存在: $(Test-Path $dir) ====="
if (Test-Path $dir) {
  Get-ChildItem $dir -Recurse -ErrorAction SilentlyContinue | Select-Object FullName,Length,LastWriteTime | Format-Table -AutoSize -Wrap
}
Write-Output "===== 本体DLL情報 ====="
$dll = 'C:\SAPIForVOICEVOX32\SAPIForVOICEVOX.DLL'
if (Test-Path $dll) {
  $f = Get-Item $dll
  Write-Output "Size=$($f.Length)  Modified=$($f.LastWriteTime)"
  # blocked (zone identifier) チェック
  $zone = Get-Content -Path $dll -Stream Zone.Identifier -ErrorAction SilentlyContinue
