input.content:
$ErrorActionPreference = 'Stop'
Write-Output ("Process bitness Is64Bit = " + [Environment]::Is64BitProcess)
try {
  $v = New-Object -ComObject SAPI.SpVoice
  $tokens = $v.GetVoices()
  Write-Output ("Voices visible to this process: " + $tokens.Count)
  $target = $null
  for ($i=0; $i -lt $tokens.Count; $i++) {
    $t = $tokens.Item($i)
    $d = $t.GetDescription()
    if ($d -like '*VOICEVOX*ずんだもん*ノーマル*') { $target = $t; break }
  }
  if ($null -eq $target) { for ($i=0; $i -lt $tokens.Count; $i++){ $t=$tokens.Item($i); if($t.GetDescription() -like '*VOICEVOX*'){ $target=$t; break } } }
  if ($null -eq $target) { Write-Output 'NO VOICEVOX TOKEN VISIBLE'; return }
  Write-Output ("Target voice: " + $target.GetDescription())
  $v.Voice = $target
  Write-Output 'Voice assigned OK'

  $stream = New-Object -ComObject SAPI.SpMemoryStream
  $fmt = New-Object -ComObject SAPI.SpAudioFormat
  $fmt.Type = 22   # SAFT22kHz16BitMono
  $stream.Format = $fmt
  Write-Output 'MemoryStream + format ready'

  $v.AudioOutputStream = $stream
  Write-Output '*** set_AudioOutputStream OK ***'

  $v.Speak('てすと', 0)
  $data = $stream.GetData()
  Write-Output ('*** Speak OK, WAV bytes = ' + $data.Length + ' ***')
}
catch {
  Write-Output ('EXCEPTION TYPE : ' + $_.Exception.GetType().FullName)
  Write-Output ('MESSAGE        : ' + $_.Exception.Message)
  if ($_.Exception.InnerException) {
    Write-Output ('INNER TYPE     : ' + $_.Exception.InnerException.GetType().FullName)
    Write-Output ('INNER MESSAGE  : ' + $_.Exception.InnerException.Message)
  }
  $hr = $null
  try { $hr = '0x{0:X8}' -f $_.Exception.HResult } catch {}
  if ($hr) { Write-Output ('HRESULT        : ' + $hr) }
}

